import React from "react";
import CardBg from "./card-bg";
import styles from "./hero-header.module.css";

const HeroHeader: React.FC = () => {
  const headerStyle = {
    backgroundImage: `url(./images/bg-hero.svg)`,
    backgroundRepeat: "no-repeat",
    backgroundSize: "cover",
    width: "100%",
    height: "780px",
  };

  return (
    <div style={headerStyle} className={styles.hero_header}>
          <div style={headerStyle} className={styles.hero_header}></div>
      <div className={styles.wrapper_card}>
        <CardBg />
      </div>
    </div>
  );
};

export default HeroHeader;
